INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('sharedquiz', 'shared_question', '{"de":{"question":"In welchem Land liegt die Sahara hauptsächlich?","answer1":"Ägypten","answer2":"Algerien","answer3":"Libyen","answer4":"Marokko","correctIndex":"1","hint":"Das flächenmäßig größte Land Afrikas."},"en":{"question":"In which country is the Sahara mainly located?","answer1":"Egypt","answer2":"Algeria","answer3":"Libya","answer4":"Morocco","correctIndex":"1","hint":"The largest country in Africa by area."},"es":{"question":"¿En qué país se encuentra principalmente el Sahara?","answer1":"Egipto","answer2":"Argelia","answer3":"Libia","answer4":"Marruecos","correctIndex":"1","hint":"El país más grande de África por superficie."},"fr":{"question":"Dans quel pays se trouve principalement le Sahara ?","answer1":"Égypte","answer2":"Algérie","answer3":"Libye","answer4":"Maroc","correctIndex":"1","hint":"Le plus grand pays d\\"},"it":{"question":"In quale paese si trova principalmente il Sahara?","answer1":"Egitto","answer2":"Algeria","answer3":"Libia","answer4":"Marocco","correctIndex":"1","hint":"Il paese più grande dell\\"},"nl":{"question":"In welk land ligt de Sahara voornamelijk?","answer1":"Egypte","answer2":"Algerije","answer3":"Libië","answer4":"Marokko","correctIndex":"1","hint":"Het grootste land van Afrika qua oppervlakte."},"pl":{"question":"W jakim kraju znajduje się głównie Sahara?","answer1":"Egipt","answer2":"Algieria","answer3":"Libia","answer4":"Maroko","correctIndex":"1","hint":"Największy kraj Afryki pod względem powierzchni."},"pt":{"question":"Em que país se encontra principalmente o Saara?","answer1":"Egito","answer2":"Argélia","answer3":"Líbia","answer4":"Marrocos","correctIndex":"1","hint":"O maior país de África em área."},"tr":{"question":"Sahra Çölü ağırlıklı olarak hangi ülkede bulunur?","answer1":"Mısır","answer2":"Cezayir","answer3":"Libya","answer4":"Fas","correctIndex":"1","hint":"Afrika\\"},"ar":{"question":"في أي بلد تقع الصحراء الكبرى بشكل رئيسي؟","answer1":"مصر","answer2":"الجزائر","answer3":"ليبيا","answer4":"المغرب","correctIndex":"1","hint":"أكبر دولة في أفريقيا مساحة."}}', 'medium', 'Geografie', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('sharedquiz', 'shared_question', '{"de":{"question":"Welcher ist der längste Fluss Europas?","answer1":"Donau","answer2":"Rhein","answer3":"Wolga","answer4":"Elbe","correctIndex":"2","hint":"Er fließt durch Russland und mündet ins Kaspische Meer."},"en":{"question":"What is the longest river in Europe?","answer1":"Danube","answer2":"Rhine","answer3":"Volga","answer4":"Elbe","correctIndex":"2","hint":"It flows through Russia and empties into the Caspian Sea."},"es":{"question":"¿Cuál es el río más largo de Europa?","answer1":"Danubio","answer2":"Rin","answer3":"Volga","answer4":"Elba","correctIndex":"2","hint":"Fluye por Rusia y desemboca en el mar Caspio."},"fr":{"question":"Quel est le plus long fleuve d\\","answer1":"Danube","answer2":"Rhin","answer3":"Volga","answer4":"Elbe","correctIndex":"2","hint":"Il traverse la Russie et se jette dans la mer Caspienne."},"it":{"question":"Qual è il fiume più lungo d\\","answer1":"Danubio","answer2":"Reno","answer3":"Volga","answer4":"Elba","correctIndex":"2","hint":"Attraversa la Russia e sfocia nel Mar Caspio."},"nl":{"question":"Wat is de langste rivier van Europa?","answer1":"Donau","answer2":"Rijn","answer3":"Wolga","answer4":"Elbe","correctIndex":"2","hint":"Hij stroomt door Rusland en mondt uit in de Kaspische Zee."},"pl":{"question":"Jaka jest najdłuższa rzeka Europy?","answer1":"Dunaj","answer2":"Ren","answer3":"Wołga","answer4":"Łaba","correctIndex":"2","hint":"Przepływa przez Rosję i wpada do Morza Kaspijskiego."},"pt":{"question":"Qual é o rio mais longo da Europa?","answer1":"Danúbio","answer2":"Reno","answer3":"Volga","answer4":"Elba","correctIndex":"2","hint":"Atravessa a Rússia e desagua no Mar Cáspio."},"tr":{"question":"Avrupa\\","answer1":"Tuna","answer2":"Ren","answer3":"Volga","answer4":"Elbe","correctIndex":"2","hint":"Rusya\\"},"ar":{"question":"ما أطول نهر في أوروبا؟","answer1":"الدانوب","answer2":"الراين