INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('sharedquiz', 'shared_question', '{"de":{"question":"Welches Meer liegt zwischen Europa und Afrika?","answer1":"Rotes Meer","answer2":"Mittelmeer","answer3":"Schwarzes Meer","answer4":"Nordsee","correctIndex":"1","hint":"Touristen fahren hierhin für Sonne und Strand."},"en":{"question":"Which sea lies between Europe and Africa?","answer1":"Red Sea","answer2":"Mediterranean Sea","answer3":"Black Sea","answer4":"North Sea","correctIndex":"1","hint":"Tourists go here for sun and beach."},"es":{"question":"¿Qué mar se encuentra entre Europa y África?","answer1":"Mar Rojo","answer2":"Mar Mediterráneo","answer3":"Mar Negro","answer4":"Mar del Norte","correctIndex":"1","hint":"Los turistas van allí por el sol y la playa."},"fr":{"question":"Quelle mer se trouve entre l\\","answer1":"Mer Rouge","answer2":"Mer Méditerranée","answer3":"Mer Noire","answer4":"Mer du Nord","correctIndex":"1","hint":"Les touristes y vont pour le soleil et la plage."},"it":{"question":"Quale mare si trova tra Europa e Africa?","answer1":"Mar Rosso","answer2":"Mar Mediterraneo","answer3":"Mar Nero","answer4":"Mare del Nord","correctIndex":"1","hint":"I turisti ci vanno per il sole e la spiaggia."},"nl":{"question":"Welke zee ligt tussen Europa en Afrika?","answer1":"Rode Zee","answer2":"Middellandse Zee","answer3":"Zwarte Zee","answer4":"Noordzee","correctIndex":"1","hint":"Toeristen gaan hier naartoe voor zon en strand."},"pl":{"question":"Jakie morze leży między Europą a Afryką?","answer1":"Morze Czerwone","answer2":"Morze Śródziemne","answer3":"Morze Czarne","answer4":"Morze Północne","correctIndex":"1","hint":"Turyści jadą tam na słońce i plażę."},"pt":{"question":"Que mar fica entre a Europa e a África?","answer1":"Mar Vermelho","answer2":"Mar Mediterrâneo","answer3":"Mar Negro","answer4":"Mar do Norte","correctIndex":"1","hint":"Os turistas vão lá pelo sol e praia."},"tr":{"question":"Avrupa ile Afrika arasında hangi deniz bulunur?","answer1":"Kızıldeniz","answer2":"Akdeniz","answer3":"Karadeniz","answer4":"Kuzey Denizi","correctIndex":"1","hint":"Turistler güneş ve plaj için oraya gider."},"ar":{"question":"أي بحر يقع بين أوروبا وأفريقيا؟","answer1":"البحر الأحمر","answer2":"البحر المتوسط","answer3":"البحر الأسود","answer4":"بحر الشمال","correctIndex":"1","hint":"يذهب إليه السياح للشمس والشاطئ."}}', 'medium', 'Geografie', true);
