INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('sharedquiz', 'shared_question', '{"de":{"question":"Welcher Kontinent ist am kältesten?","answer1":"Arktis","answer2":"Antarktis","answer3":"Grönland","answer4":"Sibirien","correctIndex":"1","hint":"Pinguine leben dort, aber keine Eisbären."},"en":{"question":"Which continent is the coldest?","answer1":"Arctic","answer2":"Antarctica","answer3":"Greenland","answer4":"Siberia","correctIndex":"1","hint":"Penguins live there, but no polar bears."},"es":{"question":"¿Cuál es el continente más frío?","answer1":"Ártico","answer2":"Antártida","answer3":"Groenlandia","answer4":"Siberia","correctIndex":"1","hint":"Los pingüinos viven allí, pero no los osos polares."},"fr":{"question":"Quel continent est le plus froid ?","answer1":"Arctique","answer2":"Antarctique","answer3":"Groenland","answer4":"Sibérie","correctIndex":"1","hint":"Les pingouins y vivent, mais pas les ours polaires."},"it":{"question":"Quale continente è il più freddo?","answer1":"Artico","answer2":"Antartide","answer3":"Groenlandia","answer4":"Siberia","correctIndex":"1","hint":"I pinguini vivono lì, ma non gli orsi polari."},"nl":{"question":"Welk continent is het koudste?","answer1":"Arctisch","answer2":"Antarctica","answer3":"Groenland","answer4":"Siberië","correctIndex":"1","hint":"Pinguïns leven er, maar geen ijsberen."},"pl":{"question":"Który kontynent jest najzimniejszy?","answer1":"Arktyka","answer2":"Antarktyka","answer3":"Grenlandia","answer4":"Syberia","correctIndex":"1","hint":"Mieszkają tam pingwiny, ale nie niedźwiedzie polarne."},"pt":{"question":"Qual é o continente mais frio?","answer1":"Ártico","answer2":"Antártida","answer3":"Gronelândia","answer4":"Sibéria","correctIndex":"1","hint":"Os pinguins vivem lá, mas não os ursos polares."},"tr":{"question":"En soğuk kıta hangisidir?","answer1":"Arktik","answer2":"Antarktika","answer3":"Grönland","answer4":"Sibirya","correctIndex":"1","hint":"Penguenler orada yaşar, ama kutup ayıları yaşamaz."},"ar":{"question":"أي قارة هي الأبرد؟","answer1":"القطب الشمالي","answer2":"أنتاركتيكا","answer3":"غرينلاند","answer4":"سيبيريا","correctIndex":"1","hint":"البطاريق تعيش هناك، لكن الدببة القطبية لا."}}', 'medium', 'Geografie', true);
