ybatıdadır."},"ar":{"question":"ما أصغر ولاية في ألمانيا؟","answer1":"هامبورغ","answer2":"سارلاند","answer3":"بريمن","answer4":"برلين","correctIndex":"2","hint":"هذه المدينة الهانزية تقع في الشمال الغربي."}}', 'medium', 'Geografie', true);
