INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('sharedquiz', 'shared_question', '{"de":{"question":"Welcher Planet ist der Sonne am nächsten?","answer1":"Venus","answer2":"Merkur","answer3":"Mars","answer4":"Erde","correctIndex":"1","hint":"Er ist auch der kleinste Planet unseres Sonnensystems."},"en":{"question":"Which planet is closest to the Sun?","answer1":"Venus","answer2":"Mercury","answer3":"Mars","answer4":"Earth","correctIndex":"1","hint":"It is also the smallest planet in our solar system."},"es":{"question":"¿Cuál es el planeta más cercano al Sol?","answer1":"Venus","answer2":"Mercurio","answer3":"Marte","answer4":"Tierra","correctIndex":"1","hint":"También es el planeta más pequeño de nuestro sistema solar."},"fr":{"question":"Quelle planète est la plus proche du Soleil ?","answer1":"Vénus","answer2":"Mercure","answer3":"Mars","answer4":"Terre","correctIndex":"1","hint":"C\\"},"it":{"question":"Quale pianeta è il più vicino al Sole?","answer1":"Venere","answer2":"Mercurio","answer3":"Marte","answer4":"Terra","correctIndex":"1","hint":"È anche il pianeta più piccolo del nostro sistema solare."},"nl":{"question":"Welke planeet staat het dichtst bij de zon?","answer1":"Venus","answer2":"Mercurius","answer3":"Mars","answer4":"Aarde","correctIndex":"1","hint":"Het is ook de kleinste planeet in ons zonnestelsel."},"pl":{"question":"Która planeta jest najbliżej Słońca?","answer1":"Wenus","answer2":"Merkury","answer3":"Mars","answer4":"Ziemia","correctIndex":"1","hint":"To także najmniejsza planeta w naszym Układzie Słonecznym."},"pt":{"question":"Qual planeta está mais perto do Sol?","answer1":"Vénus","answer2":"Mercúrio","answer3":"Marte","answer4":"Terra","correctIndex":"1","hint":"É também o menor planeta do nosso sistema solar."},"tr":{"question":"Güneş\\","answer1":"Venüs","answer2":"Merkür","answer3":"Mars","answer4":"Dünya","correctIndex":"1","hint":"Aynı zamanda güneş sistemimizin en küçük gezegenidir.