INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('sharedquiz', 'shared_question', '{"de":{"question":"Was ist schwerer: ein Kilo Federn oder ein Kilo Stahl?","answer1":"Federn","answer2":"Stahl","answer3":"Gleich schwer","answer4":"Kommt auf die Menge an","correctIndex":"2","hint":"Denkt genau nach — es steht schon in der Frage."},"en":{"question":"What weighs more: a kilo of feathers or a kilo of steel?","answer1":"Feathers","answer2":"Steel","answer3":"They weigh the same","answer4":"Depends on the amount","correctIndex":"2","hint":"Think carefully — it\\"},"es":{"question":"¿Qué pesa más: un kilo de plumas o un kilo de acero?","answer1":"Plumas","answer2":"Acero","answer3":"Pesan lo mismo","answer4":"Depende de la cantidad","correctIndex":"2","hint":"Piénsalo bien — ya está en la pregunta."},"fr":{"question":"Qu\\","answer1":"Plumes","answer2":"Acier","answer3":"Ils pèsent pareil","answer4":"Ça dépend de la quantité","correctIndex":"2","hint":"Réfléchissez bien — c\\"},"it":{"question":"Cosa pesa di più: un chilo di piume o un chilo di acciaio?","answer1":"Piume","answer2":"Acciaio","answer3":"Pesano uguale","answer4":"Dipende dalla quantità","correctIndex":"2","hint":"Pensateci bene — è già nella domanda."},"nl":{"question":"Wat is zwaarder: een kilo veren of een kilo staal?","answer1":"Veren","answer2":"Staal","answer3":"Even zwaar","answer4":"Hangt van de hoeveelheid af","correctIndex":"2","hint":"Denk goed na — het staat al in de vraag."},"pl":{"question":"Co jest cięższe: kilo piór czy kilo stali?","answer1":"Pióra","answer2":"Stal","answer3":"Ważą tyle samo","answer4":"Zależy od ilości","correctIndex":"2","hint":"Pomyśl dobrze — odpowiedź jest już w pytaniu."},"pt":{"question":"O que pesa mais: um quilo de penas ou um quilo de aço?","answer1":"Penas","answer2":"Aço","answer3":"Pesam o mesmo","answer4":"Depende da quantidade","correctIndex":"2","hint":"Pense bem — já está na pergunta."},"tr":{"question":"Hangisi daha ağır: bir kilo tüy mü yoksa bir kilo çelik mi?","answer1":"Tüy","answer2":"Çelik","answer3":"Aynı ağırlıkta","answer4":"Miktara bağlı","correctIndex":"2","hint":"İyi düşün — cevap zaten soruda."},"ar":{"question":"أيهما أثقل: كيلو ريش أم كيلو حديد؟","answer1":"ريش","answer2":"حديد","answer3":"وزنهما متساوٍ","answer4":"يعتمد على الكمية","correctIndex":"2","hint":"فكّر جيداً — الإجابة في السؤال نفسه."}}', 'medium', 'Wissenschaft', true);
