INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('sharedquiz', 'shared_question', '{"de":{"question":"Wie heißt das Gas, das wir einatmen?","answer1":"Stickstoff","answer2":"CO2","answer3":"Sauerstoff","answer4":"Wasserstoff","correctIndex":"2","hint":"Ohne dieses Gas könnten wir nicht überleben — Formel O2."},"en":{"question":"What is the gas we breathe in?","answer1":"Nitrogen","answer2":"CO2","answer3":"Oxygen","answer4":"Hydrogen","correctIndex":"2","hint":"Without this gas we couldn\\"},"es":{"question":"¿Cuál es el gas que respiramos?","answer1":"Nitrógeno","answer2":"CO2","answer3":"Oxígeno","answer4":"Hidrógeno","correctIndex":"2","hint":"Sin este gas no podríamos sobrevivir — fórmula O2."},"fr":{"question":"Quel gaz respirons-nous ?","answer1":"Azote","answer2":"CO2","answer3":"Oxygène","answer4":"Hydrogène","correctIndex":"2","hint":"Sans ce gaz, nous ne pourrions pas survivre — formule O2."},"it":{"question":"Qual è il gas che respiriamo?","answer1":"Azoto","answer2":"CO2","answer3":"Ossigeno","answer4":"Idrogeno","correctIndex":"2","hint":"Senza questo gas non potremmo sopravvivere — formula O2."},"nl":{"question":"Welk gas ademen we in?","answer1":"Stikstof","answer2":"CO2","answer3":"Zuurstof","answer4":"Waterstof","correctIndex":"2","hint":"Zonder dit gas konden we niet overleven — formule O2."},"pl":{"question":"Jaki gaz wdychamy?","answer1":"Azot","answer2":"CO2","answer3":"Tlen","answer4":"Wodór","correctIndex":"2","hint":"Bez tego gazu nie moglibyśmy przeżyć — wzór O2."},"pt":{"question":"Qual é o gás que respiramos?","answer1":"Azoto","answer2":"CO2","answer3":"Oxigénio","answer4":"Hidrogénio","correctIndex":"2","hint":"Sem este gás não poderíamos sobreviver — fórmula O2."},"tr":{"question":"Soluduğumuz gaz nedir?","answer1":"Azot","answer2":"CO2","answer3":"Oksijen","answer4":"Hidrojen","correctIndex":"2","hint":"Bu gaz olmadan hayatta kalamayız — formülü O2."},"ar":{"question":"ما الغاز الذي نتن