INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('sharedquiz', 'shared_question', '{"de":{"question":"Welches Tier kann seinen Kopf um 270 Grad drehen?","answer1":"Chamäleon","answer2":"Eule","answer3":"Flamingo","answer4":"Papagei","correctIndex":"1","hint":"Nachtaktiver Vogel mit großen Augen."},"en":{"question":"Which animal can turn its head 270 degrees?","answer1":"Chameleon","answer2":"Owl","answer3":"Flamingo","answer4":"Parrot","correctIndex":"1","hint":"Nocturnal bird with large eyes."},"es":{"question":"¿Qué animal puede girar su cabeza 270 grados?","answer1":"Camaleón","answer2":"Búho","answer3":"Flamenco","answer4":"Loro","correctIndex":"1","hint":"Ave nocturna con ojos grandes."},"fr":{"question":"Quel animal peut tourner sa tête de 270 degrés ?","answer1":"Caméléon","answer2":"Hibou","answer3":"Flamant rose","answer4":"Perroquet","correctIndex":"1","hint":"Oiseau nocturne aux grands yeux."},"it":{"question":"Quale animale può ruotare la testa di 270 gradi?","answer1":"Camaleonte","answer2":"Gufo","answer3":"Fenicottero","answer4":"Pappagallo","correctIndex":"1","hint":"Uccello notturno con occhi grandi."},"nl":{"question":"Welk dier kan zijn hoofd 270 graden draaien?","answer1":"Kameleon","answer2":"Uil","answer3":"Flamingo","answer4":"Papegaai","correctIndex":"1","hint":"Nachtelijke vogel met grote ogen."},"pl":{"question":"Jakie zwierzę może obrócić głowę o 270 stopni?","answer1":"Kameleon","answer2":"Sowa","answer3":"Flaming","answer4":"Papuga","correctIndex":"1","hint":"Nocny ptak z dużymi oczami."},"pt":{"question":"Que animal pode virar a cabeça 270 graus?","answer1":"Camaleão","answer2":"Coruja","answer3":"Flamingo","answer4":"Papagaio","correctIndex":"1","hint":"Ave noturna com olhos grandes."},"tr":{"question":"Hangi hayvan başını 270 derece çevirebilir?","answer1":"Bukalemun","answer2":"Baykuş","answer3":"Flamingo","answer4":"Papağan","correctIndex":"1","hint":"Gece aktif, büyük gözlü kuş."},"