prağını düşün."},"ar":{"question":"أي بلد لديه أكثر المناطق الزمنية؟","answer1":"روسيا","answer2":"أمريكا","answer3":"فرنسا","answer4":"الصين","correctIndex":"2","hint":"فكر في أقاليم ما وراء البحار الكثيرة لهذا البلد."}}', 'medium', 'Geografie', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('sharedquiz', 'shared_question', '{"de":{"question":"Welcher Ozean ist der tiefste?","answer1":"Atlantik","answer2":"Pazifik","answer3":"Indischer Ozean","answer4":"Arktischer Ozean","correctIndex":"1","hint":"Der Mariannengraben liegt in diesem Ozean."},"en":{"question":"Which ocean is the deepest?","answer1":"Atlantic","answer2":"Pacific","answer3":"Indian Ocean","answer4":"Arctic Ocean","correctIndex":"1","hint":"The Mariana Trench is in this ocean."},"es":{"question":"¿Cuál es el océano más profundo?","answer1":"Atlántico","answer2":"Pacífico","answer3":"Océano Índico","answer4":"Océano Ártico","correctIndex":"1","hint":"La Fosa de las Marianas está en este océano."},"fr":{"question":"Quel océan est le plus profond ?","answer1":"Atlantique","answer2":"Pacifique","answer3":"Océan Indien","answer4":"Océan Arctique","correctIndex":"1","hint":"La fosse des Mariannes se trouve dans cet océan."},"it":{"question":"Quale oceano è il più profondo?","answer1":"Atlantico","answer2":"Pacifico","answer3":"Oceano Indiano","answer4":"Oceano Artico","correctIndex":"1","hint":"La Fossa delle Marianne si trova in questo oceano."},"nl":{"question":"Welke oceaan is het diepst?","answer1":"Atlantische","answer2":"Stille","answer3":"Indische Oceaan","answer4":"Noordelijke IJszee","correctIndex":"1","hint":"De Marianentrog ligt in deze oceaan."},"pl":{"question":"Który ocean jest najgłębszy?","answer1":"Atlantyk","answer2":"Pacyfik","answer3":"Ocean Indyjski","answer4":"Ocean Arktyczny","correctIndex":"1","hint":"Rów Mariański znajduje się w tym oceanie."},"pt":{"question":"Qual oceano é o mais profundo?","answer1":"Atlântico","answer2":"Pacífico","answer3":"Oceano Índico","answer4":"Oceano Ártico","correctIndex":"1","hint":"A Fossa das Marianas fica neste oceano."},"tr":{"question":"En derin okyanus hangisidir?","answer1":"Atlantik","answer2":"Pasifik","answer3":"Hint Okyanusu","answer4":"Kuzey Buz Denizi","correctIndex":"1","hint":"Mariana Çukuru bu okyanustadır."},"ar":{"question":"أي محيط هو الأعمق؟","answer1":"الأطلسي","answer2":"الهادئ","answer3":"المحيط الهندي","answer4":"المحيط المتجمد الشمالي","correctIndex":"1","hint":"خندق ماريانا يقع في هذا المحيط."}}', 'medium', 'Geografie', true);
