INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('sharedquiz', 'shared_question', '{"de":{"question":"Wie viele Zähne hat ein Erwachsener inklusive Weisheitszähne?","answer1":"28","answer2":"30","answer3":"32","answer4":"36","correctIndex":"2","hint":"Vier davon kommen oft erst spät und werden manchmal gezogen."},"en":{"question":"How many teeth does an adult have including wisdom teeth?","answer1":"28","answer2":"30","answer3":"32","answer4":"36","correctIndex":"2","hint":"Four of them often come late and are sometimes pulled."},"es":{"question":"¿Cuántos dientes tiene un adulto incluyendo las muelas del juicio?","answer1":"28","answer2":"30","answer3":"32","answer4":"36","correctIndex":"2","hint":"Cuatro de ellos suelen salir tarde y a veces se extraen."},"fr":{"question":"Combien de dents un adulte a-t-il, dents de sagesse comprises ?","answer1":"28","answer2":"30","answer3":"32","answer4":"36","correctIndex":"2","hint":"Quatre d\\"},"it":{"question":"Quanti denti ha un adulto compresi quelli del giudizio?","answer1":"28","answer2":"30","answer3":"32","answer4":"36","correctIndex":"2","hint":"Quattro di essi arrivano spesso tardi e a volte vengono estratti."},"nl":{"question":"Hoeveel tanden heeft een volwassene inclusief verstandskiezen?","answer1":"28","answer2":"30","answer3":"32","answer4":"36","correctIndex":"2","hint":"Vier ervan komen vaak laat en worden soms getrokken."},"pl":{"question":"Ile zębów ma dorosły łącznie z zębami mądrości?","answer1":"28","answer2":"30","answer3":"32","answer4":"36","correctIndex":"2","hint":"Cztery z nich często pojawiają się późno i bywają usuwane."},"pt":{"question":"Quantos dentes tem um adulto incluindo os do siso?","answer1":"28","answer2":"30","answer3":"32","answer4":"36","correctIndex":"2","hint":"Quatro deles costumam nascer tarde e às vezes são extraídos."},"tr":{"question":"Yetişkinin yirmi yaş dişleri dahil kaç dişi vardır?","answer1":"28","answer2":"30","answer3":"32","answer4":"36","correctIndex":"2","hint":"Dördü genellikle geç gelir ve bazen çekilir."},"ar":{"question":"كم سناً للبالغ مع أضراس العقل؟","answer1":"28","answer2":"30","answer3":"32","answer4":"36","correctIndex":"2","hint":"أربعة منها تأتي متأخرة وأحياناً تُخلع."}}', 'medium', 'Wissenschaft', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('sharedquiz', 'shared_question', '{"de":{"question":"Wer komponierte \"Die Zauberflöte\"?","answer1":"Bach","answer2":"Beethoven","answer3":"Mozart","answer4":"Händel","correctIndex":"2","hint":"Ein Wunderkind aus Salzburg."},"en":{"question":"Who composed \"The Magic Flute\"?","answer1":"Bach","answer2":"Beethoven","answer3":"Mozart","answer4":"Handel","correctIndex":"2","hint":"A child prodigy from Salzburg."},"es":{"question":"¿Quién compuso \"La Flauta Mágica\"?","answer1":"Bach","answer2":"Beethoven","answer3":"Mozart","answer4":"Händel","correctIndex":"2","hint":"Un niño prodigio de Salzburgo."},"fr":{"question":"Qui a composé « La Flûte enchantée » ?","answer1":"Bach","answer2":"Beethoven","answer3":"Mozart","answer4":"Haendel","correctIndex":"2","hint":"Un enfant prodige de Salzbourg."},"it":{"question":"Chi ha composto \"Il Flauto Magico\"?","answer1":"Bach","answer2":"Beethoven","answer3":"Mozart","answer4":"Händel","correctIndex":"2","hint":"Un bambino prodigio di Salisburgo."},"nl":{"question":"Wie componeerde \"De Toverfluit\"?","answer1":"Bach","answer2":"Beethoven","answer3":"Mozart","answer4":"Händel","correctIndex":"2","hint":"Een wonderkind uit Salzburg."},"pl":{"question":"Kto skomponował „Czarodziejski flet\"?","answer1":"Bach","answer2":"Beethoven","answer3":"Mozart","answer4":"Händel","correctIndex":"2","hint":"Cudowne dziecko z Salzburga."},"pt":{"question":"Quem compôs \"A Flauta Mágica\"?","answer1":"Bach","answer2":"Beethoven","answer3":"Mozart","answer4":"Händel","correctIndex":"2","hint":"Um menino prodígio de Salzburgo."},"tr":{"question":"\"Sihirli Flüt\"ü kim besteledi?","answer1":"Bach","answer2":"Beethoven","answer3":"Mozart","answer4":"Händel","correctIndex":"2","hint":"Salzburg\\"},"ar":{"question":"من ألّف \"الناي السحري\"؟","answer1":"باخ","answer2":"بيتهوفن","answer3":"موتسارت","answer4":"هيندل","correctIndex":"2","hint":"طفل معجزة