INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('sharedquiz', 'shared_question', '{"de":{"question":"Welches Land produziert den meisten Käse?","answer1":"Frankreich","answer2":"Schweiz","answer3":"USA","answer4":"Deutschland","correctIndex":"2","hint":"Es ist nicht das Land, das man typischerweise mit Käse verbindet."},"en":{"question":"Which country produces the most cheese?","answer1":"France","answer2":"Switzerland","answer3":"USA","answer4":"Germany","correctIndex":"2","hint":"It\\"},"es":{"question":"¿Qué país produce más queso?","answer1":"Francia","answer2":"Suiza","answer3":"EE.UU.","answer4":"Alemania","correctIndex":"2","hint":"No es el país típicamente asociado con el queso."},"fr":{"question":"Quel pays produit le plus de fromage ?","answer1":"France","answer2":"Suisse","answer3":"États-Unis","answer4":"Allemagne","correctIndex":"2","hint":"Ce n\\"},"it":{"question":"Quale paese produce più formaggio?","answer1":"Francia","answer2":"Svizzera","answer3":"USA","answer4":"Germania","correctIndex":"2","hint":"Non è il paese tipicamente associato al formaggio."},"nl":{"question":"Welk land produceert de meeste kaas?","answer1":"Frankrijk","answer2":"Zwitserland","answer3":"VS","answer4":"Duitsland","correctIndex":"2","hint":"Het is niet het land dat je typisch met kaas associeert."},"pl":{"question":"Który kraj produkuje najwięcej sera?","answer1":"Francja","answer2":"Szwajcaria","answer3":"USA","answer4":"Niemcy","correctIndex":"2","hint":"To nie jest kraj typowo kojarzony z serem."},"pt":{"question":"Que país produz mais queijo?","answer1":"França","answer2":"Suíça","answer3":"EUA","answer4":"Alemanha","correctIndex":"2","hint":"Não é o país tipicamente associado ao queijo."},"tr":{"question":"En çok peynir üreten ülke hangisidir?","answer1":"Fransa","answer2":"İsviçre","answer3":"ABD","answer4":"Almanya","correctIndex":"2","hint":"Peynirle tipik olarak ilişkilendirilen ülke değildir."},"ar":{"question":"أ