INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('sharedquiz', 'shared_question', '{"de":{"question":"Wer schrieb \"Romeo und Julia\"?","answer1":"Goethe","answer2":"Shakespeare","answer3":"Schiller","answer4":"Molière","correctIndex":"1","hint":"Ein englischer Dramatiker aus dem 16. Jahrhundert."},"en":{"question":"Who wrote \"Romeo and Juliet\"?","answer1":"Goethe","answer2":"Shakespeare","answer3":"Schiller","answer4":"Molière","correctIndex":"1","hint":"An English playwright from the 16th century."},"es":{"question":"¿Quién escribió \"Romeo y Julieta\"?","answer1":"Goethe","answer2":"Shakespeare","answer3":"Schiller","answer4":"Molière","correctIndex":"1","hint":"Un dramaturgo inglés del siglo XVI."},"fr":{"question":"Qui a écrit « Roméo et Juliette » ?","answer1":"Goethe","answer2":"Shakespeare","answer3":"Schiller","answer4":"Molière","correctIndex":"1","hint":"Un dramaturge anglais du XVIe siècle."},"it":{"question":"Chi ha scritto \"Romeo e Giulietta\"?","answer1":"Goethe","answer2":"Shakespeare","answer3":"Schiller","answer4":"Molière","correctIndex":"1","hint":"Un drammaturgo inglese del XVI secolo."},"nl":{"question":"Wie schreef \"Romeo en Julia\"?","answer1":"Goethe","answer2":"Shakespeare","answer3":"Schiller","answer4":"Molière","correctIndex":"1","hint":"Een Engelse toneelschrijver uit de 16e eeuw."},"pl":{"question":"Kto napisał „Romeo i Julię\"?","answer1":"Goethe","answer2":"Shakespeare","answer3":"Schiller","answer4":"Molier","correctIndex":"1","hint":"Angielski dramaturg z XVI wieku."},"pt":{"question":"Quem escreveu \"Romeu e Julieta\"?","answer1":"Goethe","answer2":"Shakespeare","answer3":"Schiller","answer4":"Molière","correctIndex":"1","hint":"Um dramaturgo inglês do século XVI."},"tr":{"question":"\"Romeo ve Juliet\"i kim yazdı?","answer1":"Goethe","answer2":"Shakespeare","answer3":"Schiller","answer4":"Molière","correctIndex":"1","hint":"16. yüzyıldan bir İngiliz oyun yazarı."},"ar":{"question":"من كتب \"روميو وجولييت\"؟","answer1":"غوته","answer2":"شكسبير","answer3":"شيلر","answer4":"موليير","correctIndex":"1","hint":"كاتب مسرحي إنجليزي من القرن السادس عشر."}}', 'medium', 'Geschichte', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('sharedquiz', 'shared_question', '{"de":{"question":"Welches Gas lässt die Stimme höher klingen?","answer1":"Stickstoff","answer2":"Sauerstoff","answer3":"Helium","answer4":"Wasserstoff","correctIndex":"2","hint":"Es wird auch für Luftballons verwendet."},"en":{"question":"Which gas makes your voice sound higher?","answer1":"Nitrogen","answer2":"Oxygen","answer3":"Helium","answer4":"Hydrogen","correctIndex":"2","hint":"It\\"},"es":{"question":"¿Qué gas hace que la voz suene más aguda?","answer1":"Nitrógeno","answer2":"Oxígeno","answer3":"Helio","answer4":"Hidrógeno","correctIndex":"2","hint":"También se usa para globos."},"fr":{"question":"Quel gaz rend la voix plus aiguë ?","answer1":"Azote","answer2":"Oxygène","answer3":"Hélium","answer4":"Hydrogène","correctIndex":"2","hint":"On l\\"},"it":{"question":"Quale gas rende la voce più acuta?","answer1":"Azoto","answer2":"Ossigeno","answer3":"Elio","answer4":"Idrogeno","correctIndex":"2","hint":"Viene usato anche per i palloncini."},"nl":{"question":"Welk gas maakt je stem hoger?","answer1":"Stikstof","answer2":"Zuurstof","answer3":"Helium","answer4":"Waterstof","correctIndex":"2","hint":"Het wordt ook voor ballonnen gebruikt."},"pl":{"question":"Jaki gaz sprawia, że głos brzmi wyżej?","answer1":"Azot","answer2":"Tlen","answer3":"Hel","answer4":"Wodór","correctIndex":"2","hint":"Używany jest też do balonów."},"pt":{"question":"Que gás torna a voz mais aguda?","answer1":"Azoto","answer2":"Oxigénio","answer3":"Hélio","answer4":"Hidrogénio","correctIndex":"2","hint":"Também é usado para balões."},"tr":{"question":"Hangi gaz sesi daha tiz yapar?","answer1":"Azot","answer2":"Oksijen","answer3":"Helyum","answer4":"Hidrojen","correctIndex":"2","hint":"Balon şişirmek için de kullanılır."},"ar":{"question":"أي غاز يجعل الصوت أكثر حدة؟","answer1":"نيتروجين","answer2":"أكسجين","answer3":"هيليوم","answer4":"هيدروجين","correctIndex":"2","hint":"يُستخدم أيضاً للبالونات."}}', 'medium', 'Wissenschaft', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('sharedquiz', 'shared_question', '{"de":{"question":"In welchem Land wurde der Fußball erfunden?","answer1":"Brasilien","answer2":"Deutschland","answer3":"England","answer4":"Spanien","correctIndex":"2","hint":"Die Premier League kommt aus diesem Land."},"en":{"question":"In which country was football invented?","answer1":"Brazil","answer2":"Germany","answer3":"England","answer4":"Spain","correctIndex":"2","hint":"The Premier League comes from this country."},"es":{"question":"¿En qué país se inventó el fútbol?","answer1":"Brasil","answer2":"Alemania","answer3":"Inglaterra","answer4":"España","correctIndex":"2","hint":"La Premier League es de este país."},"fr":{"question":"Dans quel pays le football a-t-il été inventé ?","answer1":"Brésil","answer2":"Allemagne","answer3":"Angleterre","answer4":"Espagne","correctIndex":"2","hint":"La Premier League vient de ce pays."},"it":{"question":"In quale paese è stato inventato il calcio?","answer1":"Brasile","answer2":"Germania","answer3":"Inghilterra","answer4":"Spagna","correctIndex":"2","hint":"La Premier League viene da questo paese."},"nl":{"question":"In welk land is voetbal uitgevonden?","answer1":"Brazilië","answer2":"Duitsland","answer3":"Engeland","answer4":"Spanje","correctIndex":"2","hint":"De Premier League komt uit dit land."},"pl":{"question":"W jakim kraju wynaleziono piłkę nożną?","answer1":"Brazylia","answer2":"Niemcy","answer3":"Anglia","answer4":"Hiszpania","correctIndex":"2","hint":"Premier League pochodzi z tego kraju."},"pt":{"question":"Em que país foi inventado o futebol?","answer1":"Brasil","answer2":"Alemanha","answer3":"Inglaterra","answer4":"Espanha","correctIndex":"2","hint":"A Premier League é deste país."},"tr":{"question":"Futbol hangi ülkede icat edildi?","answer1":"Brezilya","answer2":"Almanya","answer3":"İngiltere","answer4":"İspanya","correctIndex":"2","hint":"Premier Lig bu ülkeden gelir."},