INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('sharedquiz', 'shared_question', '{"de":{"question":"Welcher Vogel kann am tiefsten tauchen?","answer1":"Albatros","answer2":"Pinguin","answer3":"Pelikan","answer4":"Kormoran","correctIndex":"1","hint":"Ein flugunfähiger Vogel, der in der Antarktis lebt."},"en":{"question":"Which bird can dive the deepest?","answer1":"Albatross","answer2":"Penguin","answer3":"Pelican","answer4":"Cormorant","correctIndex":"1","hint":"A flightless bird that lives in Antarctica."},"es":{"question":"¿Qué ave puede bucear más profundo?","answer1":"Albatros","answer2":"Pingüino","answer3":"Pelícano","answer4":"Cormorán","correctIndex":"1","hint":"Un ave que no vuela y vive en la Antártida."},"fr":{"question":"Quel oiseau peut plonger le plus profondément ?","answer1":"Albatros","answer2":"Manchot","answer3":"Pélican","answer4":"Cormoran","correctIndex":"1","hint":"Un oiseau incapable de voler qui vit en Antarctique."},"it":{"question":"Quale uccello può immergersi più in profondità?","answer1":"Albatros","answer2":"Pinguino","answer3":"Pellicano","answer4":"Cormorano","correctIndex":"1","hint":"Un uccello che non vola e vive in Antartide."},"nl":{"question":"Welke vogel kan het diepst duiken?","answer1":"Albatros","answer2":"Pinguïn","answer3":"Pelikaan","answer4":"Aalscholver","correctIndex":"1","hint":"Een vogel die niet kan vliegen en in Antarctica leeft."},"pl":{"question":"Jaki ptak może nurkować najgłębiej?","answer1":"Albatros","answer2":"Pingwin","answer3":"Pelikan","answer4":"Kormoran","correctIndex":"1","hint":"Nielotny ptak żyjący na Antarktydzie."},"pt":{"question":"Que ave pode mergulhar mais fundo?","answer1":"Albatroz","answer2":"Pinguim","answer3":"Pelicano","answer4":"Corvo-marinho","correctIndex":"1","hint":"Uma ave que não voa e vive na Antártida."},"tr":{"question":"En derinden dalabilen kuş hangisidir?","answer1":"Albatros","answer2":"Penguen","answer3":"Pelikan","answer4":"Karabatak","correctIndex":"1","hint":"Uçamayan ve Antarktika\\"},"ar":{"question":"أي طائر يمكنه الغوص أعمق؟","answer1":"قطرس","answer2":"بطريق","answer3":"بجعة","answer4":"غاق","correctIndex":"1","hint":"طائر لا يطير يعيش في أنتاركتيكا."}}', 'medium', 'Wissenschaft', true);
