"answer2":"Tarantula","answer3":"Golyat kuşyiyen","answer4":"Tarantula","correctIndex":"2","hint":"Bacak açıklığı 30 cm\\"},"ar":{"question":"ما أكبر عنكبوت في العالم؟","answer1":"الأرملة السوداء","answer2":"رتيلاء","answer3":"رتيلاء جالوت","answer4":"طرنطولا","correctIndex":"2","hint":"يمكن أن يصل مدى أرجلها إلى 30 سم."}}', 'medium', 'Wissenschaft', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('sharedquiz', 'shared_question', '{"de":{"question":"Welche Frucht hat die meisten Kerne?","answer1":"Wassermelone","answer2":"Granatapfel","answer3":"Kiwi","answer4":"Erdbeere","correctIndex":"3","hint":"Die Kerne sind außen — im Durchschnitt etwa 200 pro Frucht."},"en":{"question":"Which fruit has the most seeds?","answer1":"Watermelon","answer2":"Pomegranate","answer3":"Kiwi","answer4":"Strawberry","correctIndex":"3","hint":"The seeds are on the outside — about 200 per fruit on average."},"es":{"question":"¿Qué fruta tiene más semillas?","answer1":"Sandía","answer2":"Granada","answer3":"Kiwi","answer4":"Fresa","correctIndex":"3","hint":"Las semillas están por fuera — unas 200 por fruta en promedio."},"fr":{"question":"Quel fruit a le plus de graines ?","answer1":"Pastèque","answer2":"Grenade","answer3":"Kiwi","answer4":"Fraise","correctIndex":"3","hint":"Les graines sont à l\\"},"it":{"question":"Quale frutto ha più semi?","answer1":"Anguria","answer2":"Melograno","answer3":"Kiwi","answer4":"Fragola","correctIndex":"3","hint":"I semi sono all\\"},"nl":{"question":"Welk fruit heeft de meeste zaden?","answer1":"Watermeloen","answer2":"Granaatappel","answer3":"Kiwi","answer4":"Aardbei","correctIndex":"3","hint":"De zaden zitten aan de buitenkant — gemiddeld zo\\"},"pl":{"question":"Jaki owoc ma najwięcej nasion?","answer1":"Arbuz","answer2":"Granat","answer3":"Kiwi","answer4":"Truskawka","correctIndex":"3","hint":"Nasiona są na zewnątrz — średnio ok. 200 na owoc."},"pt":{"question":"Que fruta tem mais sementes?","answer1":"Melancia","answer2":"Romã","answer3":"Kiwi","answer4":"Morango","correctIndex":"3","hint":"As sementes estão no exterior — cerca de 200 por fruta em média."},"tr":{"question":"En çok çekirdeğe sahip meyve hangisidir?","answer1":"Karpuz","answer2":"Nar","answer3":"Kivi","answer4":"Çilek","correctIndex":"3","hint":"Çekirdekler dışarıda — meyve başına o