INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('sharedquiz', 'shared_question', '{"de":{"question":"Welches Metall ist am häufigsten in der Erdkruste?","answer1":"Eisen","answer2":"Aluminium","answer3":"Kupfer","answer4":"Gold","correctIndex":"1","hint":"Es wird für Dosen und Flugzeuge verwendet."},"en":{"question":"Which metal is most abundant in the Earth\\","answer1":"Iron","answer2":"Aluminium","answer3":"Copper","answer4":"Gold","correctIndex":"1","hint":"It\\"},"es":{"question":"¿Qué metal es más abundante en la corteza terrestre?","answer1":"Hierro","answer2":"Aluminio","answer3":"Cobre","answer4":"Oro","correctIndex":"1","hint":"Se usa para latas y aviones."},"fr":{"question":"Quel métal est le plus abondant dans la croûte terrestre ?","answer1":"Fer","answer2":"Aluminium","answer3":"Cuivre","answer4":"Or","correctIndex":"1","hint":"Il est utilisé pour les canettes et les avions."},"it":{"question":"Quale metallo è più abbondante nella crosta terrestre?","answer1":"Ferro","answer2":"Alluminio","answer3":"Rame","answer4":"Oro","correctIndex":"1","hint":"Viene usato per lattine e aerei."},"nl":{"question":"Welk metaal komt het meest voor in de aardkorst?","answer1":"IJzer","answer2":"Aluminium","answer3":"Koper","answer4":"Goud","correctIndex":"1","hint":"Het wordt gebruikt voor blikjes en vliegtuigen."},"pl":{"question":"Jaki metal jest najbardziej rozpowszechniony w skorupie ziemskiej?","answer1":"Żelazo","answer2":"Aluminium","answer3":"Miedź","answer4":"Złoto","correctIndex":"1","hint":"Używany do puszek i samolotów."},"pt":{"question":"Que metal é mais abundante na crosta terrestre?","answer1":"Ferro","answer2":"Alumínio","answer3":"Cobre","answer4":"Ouro","correctIndex":"1","hint":"É usado para latas e aviões."},"tr":{"question":"Yer kabuğunda en bol bulunan metal hangisidir?","answer1":"Demir","answer2":"Alüminyum","answer3":"Bakır","answer4":"Altın","correctIndex":"1","hint":"Teneke kutular ve uçaklar için kullanılır."},"ar":{"question":"أي معدن هو الأكثر وفرة في القشرة الأرضية؟","answer1":"حديد","answer2":"ألومنيوم","answer3":"نحاس","answer4":"ذهب","correctIndex":"1","hint":"يُستخدم في العلب والطائرات."}}', 'medium', 'Wissenschaft', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('sharedquiz', 'shared_question', '{"de":{"question":"Welcher Kontinent hat keine Wüste?","answer1":"Europa","answer2":"Südamerika","answer3":"Australien","answer4":"Keiner — alle haben Wüsten","correctIndex":"0","hint":"Der zweitkleinste Kontinent."},"en":{"question":"Which continent has no desert?","answer1":"Europe","answer2":"South America","answer3":"Australia","answer4":"None — all have deserts","correctIndex":"0","hint":"The second smallest continent."},"es":{"question":"¿Qué continente no tiene desierto?","answer1":"Europa","answer2":"Sudamérica","answer3":"Australia","answer4":"Ninguno — todos tienen desiertos","correctIndex":"0","hint":"El segundo continente más pequeño."},"fr":{"question":"Quel continent n\\","answer1":"Europe","answer2":"Amérique du Sud","answer3":"Australie","answer4":"Aucun — tous en ont","correctIndex":"0","hint":"Le deuxième plus petit continent."},"it":{"question":"Quale continente non ha deserti?","answer1":"Europa","answer2":"Sud America","answer3":"Australia","answer4":"Nessuno — tutti ne hanno","correctIndex":"0","hint":"Il secondo continente più piccolo."},"nl":{"question":"Welk continent heeft geen woestijn?","answer1":"Europa","answer2":"Zuid-Amerika","answer3":"Australië","answer4":"Geen — allemaal hebben ze woestijnen","correctIndex":"0","hint":"Het op één na kleinste continent."},"pl":{"question":"Który kontynent nie ma pustyni?","answer1":"Europa","answer2":"Ameryka Południowa","answer3":"Australia","answer4":"Żaden — wszystkie mają pustynie","correctIndex":"0","hint":"Drugi najmniejszy kontynent."},"pt":{"question":"Que continente não tem deserto?","answer1":"Europa","answer2":"América do Sul","answer3":"Austrália","answer4":"Nenhum — todos têm desertos","correctIndex":"0","hint":"O segundo menor continente."},"tr":{"question":"Hangi kıtada çöl yoktur?","answer1":"Avrupa","answer2":"Güney Amerika","answer3":"Avustralya","answer4":"Hiçbiri — hepsinde çöl var","correctIndex":"0","hint":"İkinci en küçük kıta."},"ar":{"question":"أي قارة ليس فيها صحراء؟","answer1":"أوروبا","answer2":"أمريكا الجنوبية","answer3":"أستراليا","answer4":"لا شيء — كلها فيها صحارى","correctIndex":"0","hint":"ثاني أصغر قارة."}}', 'medium', 'Geografie', true);
