INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('sharedquiz', 'shared_question', '{"de":{"question":"In welchem Film sagt man \"Möge die Macht mit dir sein\"?","answer1":"Star Trek","answer2":"Star Wars","answer3":"Matrix","answer4":"Herr der Ringe","correctIndex":"1","hint":"Lichtschwerter und Jedis spielen eine große Rolle."},"en":{"question":"In which film do they say \"May the Force be with you\"?","answer1":"Star Trek","answer2":"Star Wars","answer3":"The Matrix","answer4":"Lord of the Rings","correctIndex":"1","hint":"Lightsabers and Jedi play a big role."},"es":{"question":"¿En qué película dicen \"Que la Fuerza te acompañe\"?","answer1":"Star Trek","answer2":"Star Wars","answer3":"Matrix","answer4":"El Señor de los Anillos","correctIndex":"1","hint":"Los sables de luz y los Jedi juegan un papel importante."},"fr":{"question":"Dans quel film dit-on « Que la Force soit avec toi » ?","answer1":"Star Trek","answer2":"Star Wars","answer3":"Matrix","answer4":"Le Seigneur des Anneaux","correctIndex":"1","hint":"Les sabres laser et les Jedi y jouent un rôle important."},"it":{"question":"In quale film si dice \"Che la Forza sia con te\"?","answer1":"Star Trek","answer2":"Star Wars","answer3":"Matrix","answer4":"Il Signore degli Anelli","correctIndex":"1","hint":"Le spade laser e i Jedi hanno un ruolo importante."},"nl":{"question":"In welke film zegt men \"Moge de Kracht met je zijn\"?","answer1":"Star Trek","answer2":"Star Wars","answer3":"The Matrix","answer4":"In de Ban van de Ring","correctIndex":"1","hint":"Lichtzwaarden en Jedi spelen een grote rol."},"pl":{"question":"W jakim filmie mówią „Niech Moc będzie z tobą\"?","answer1":"Star Trek","answer2":"Gwiezdne Wojny","answer3":"Matrix","answer4":"Władca Pierścieni","correctIndex":"1","hint":"Miecze świetlne i Jedi odgrywają ważną rolę."},"pt":{"question":"Em que filme se diz \"Que a Força esteja contigo\"?","answer1":"Star Trek","answer2":"Star Wars","answer3":"Matrix","answer4":"O Senhor dos Anéis","correctIndex":"1","hint":"Sabres de luz e Jedi têm um papel importante."},"tr":{"question":"Hangi filmde \"Güç seninle olsun\" denir?","answer1":"Star Trek","answer2":"Yıldız Savaşları","answer3":"Matrix","answer4":"Yüzüklerin Efendisi","correctIndex":"1","hint":"Işın kılıçları ve Jedi\\"},"ar":{"question":"في أي فيلم يقولون \"لتكن القوة معك\"؟","answer1":"ستار تريك","answer2":"حرب النجوم","answer3":"ماتريكس","answer4":"سيد الخواتم","correctIndex":"1","hint":"السيوف الضوئية والجيداي يلعبون دوراً كبيراً."}}', 'medium', 'Unterhaltung', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('sharedquiz', 'shared_question', '{"de":{"question":"Welches Tier hat den größten Augen im Tierreich?","answer1":"Elefant","answer2":"Strauss","answer3":"Riesenkalmar","answer4":"Adler","correctIndex":"2","hint":"Seine Augen können so groß wie ein Fußball werden."},"en":{"question":"Which animal has the largest eyes in the animal kingdom?","answer1":"Elephant","answer2":"Ostrich","answer3":"Giant Squid","answer4":"Eagle","correctIndex":"2","hint":"Its eyes can be as big as a football."},"es":{"question":"¿Qué animal tiene los ojos más grandes del reino animal?","answer1":"Elefante","answer2":"Avestruz","answer3":"Calamar gigante","answer4":"Águila","correctIndex":"2","hint":"Sus ojos pueden ser tan grandes como un balón de fútbol."},"fr":{"question":"Quel animal a les plus grands yeux du règne animal ?","answer1":"Éléphant","answer2":"Autruche","answer3":"Calmar géant","answer4":"Aigle","correctIndex":"2","hint":"Ses yeux peuvent être aussi grands qu\\"},"it":{"question":"Quale animale ha gli occhi più grandi nel regno animale?","answer1":"Elefante","answer2":"Struzzo","answer3":"Calamaro gigante","answer4":"Aquila","correctIndex":"2","hint":"I suoi occhi possono essere grandi come un pallone da calcio."},"nl":{"question":"Welk dier heeft de grootste ogen in het dierenrijk?","answer1":"Olifant","answer2":"Struisvogel","answer3":"Reuzeninktvis","answer4":"Adelaar","correctIndex":"2","hint":"Zijn ogen kunnen zo groot zijn als een voetbal."},"pl":{"question":"Jakie zwierzę ma największe oczy w królestwie zwierząt?","answer1":"Słoń","answer2":"Struś","answer3":"Kałamarnica olbrzymia","answer4":"Orzeł","correctIndex":"2","hint":"Jej oczy mogą być duże jak piłka nożna."},"pt":{"question":"Que animal tem os maiores olhos no reino animal?","answer1":"Elefante","answer2":"Avestruz","answer3":"Lula gigante","answer4":"Águia","correctIndex":"2","hint":"Os seus olhos podem ser tão