INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('sharedquiz', 'shared_question', '{"de":{"question":"Welcher Feiertag wird am 31. Oktober gefeiert?","answer1":"Nikolaus","answer2":"Halloween","answer3":"Reformationstag","answer4":"Beide B und C","correctIndex":"3","hint":"In Deutschland ist es ein kirchlicher Feiertag, international verkleidet man sich."},"en":{"question":"Which holiday is celebrated on 31 October?","answer1":"St. Nicholas Day","answer2":"Halloween","answer3":"Reformation Day","answer4":"Both B and C","correctIndex":"3","hint":"In Germany it\\"},"es":{"question":"¿Qué festividad se celebra el 31 de octubre?","answer1":"San Nicolás","answer2":"Halloween","answer3":"Día de la Reforma","answer4":"Ambas B y C","correctIndex":"3","hint":"En Alemania es un día festivo religioso, internacionalmente la gente se disfraza."},"fr":{"question":"Quelle fête est célébrée le 31 octobre ?","answer1":"Saint-Nicolas","answer2":"Halloween","answer3":"Jour de la Réforme","answer4":"Les deux B et C","correctIndex":"3","hint":"En Allemagne c\\"},"it":{"question":"Quale festività si celebra il 31 ottobre?","answer1":"San Nicola","answer2":"Halloween","answer3":"Giorno della Riforma","answer4":"Sia B che C","correctIndex":"3","hint":"In Germania è una festa religiosa, a livello internazionale ci si traveste."},"nl":{"question":"Welke feestdag wordt op 31 oktober gevierd?","answer1":"Sinterklaas","answer2":"Halloween","answer3":"Hervormingsdag","answer4":"Beide B en C","correctIndex":"3","hint":"In Duitsland is het een kerkelijke feestdag, internationaal verkleden mensen zich."},"pl":{"question":"Jakie święto obchodzone jest 31 października?","answer1":"Mikołajki","answer2":"Halloween","answer3":"Dzień Reformacji","answer4":"Oba B i C","correctIndex":"3","hint":"W Niemczech to święto kościelne, na świecie ludzie się przebierają."},"pt":{"question":"Que feriado se celebra a 31 de outubro?","answer1":"São Nicolau","answer2":"Halloween","answer3":"Dia da Reforma","answer4":"Ambos B e C","correctIndex":"3","hint":"Na Alemanha é feriado religioso, internacionalmente as pessoas mascaram-se."},"tr":{"question":"31 Ekim\\","answer1":"Noel Baba","answer2":"Cadılar Bayramı","answer3":"Reform Günü","answer4":"B ve C ikisi de","correctIndex":"3","hint":"Almanya\\"},"ar":{"question":"أي عطلة تُحتفل بها في 31 أكتوبر؟","answer1":"عيد القديس نيكولاس","answer2":"هالوين","answer3":"يوم الإصلاح","answer4":"كلاهما ب و ج","correctIndex":"3","hint":"في ألمانيا عطلة دينية، وعالمياً يرتدي الناس أزياء تنكرية."}}', 'medium', 'Allgemeinwissen', true);
